import{_ as i,o as e,c as s,ak as t,am as n}from"./chunks/framework.B9OfcISu.js";const k=JSON.parse('{"title":"Micromamba","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"setup/package-managers/micromamba.md","filePath":"setup/package-managers/micromamba.md"}'),l={name:"setup/package-managers/micromamba.md"};function o(r,a,c,h,m,p){return e(),s("div",null,[...a[0]||(a[0]=[t('<h1 id="micromamba" tabindex="-1"><img src="'+n+`" style="display:inline-block;vertical-align:middle;height:48px;margin-right:8px;"> Micromamba <a class="header-anchor" href="#micromamba" aria-label="Permalink to ŌĆ£MicromambaŌĆØ">ŌĆŗ</a></h1><p>Micromamba is a statically linked C++ executable that provides the full power of the Conda ecosystem without needing a pre-installed Python &quot;base&quot; environment. Unlike pip, uv and other package managers, Conda can manage libraries written in C, C++, or R, which is vital for machine learning and AI work.</p><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p><strong>When to use:</strong> Micromamba is preferred for projects requiring polyglot or non-Python dependencies; for repositories strictly focused on the Python ecosystem, <a href="./uv.html">uv</a> remains the optimized choice.</p></div><h2 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to ŌĆ£InstallationŌĆØ">ŌĆŗ</a></h2><h3 id="arch-linux" tabindex="-1">Arch Linux <a class="header-anchor" href="#arch-linux" aria-label="Permalink to ŌĆ£Arch LinuxŌĆØ">ŌĆŗ</a></h3><p><strong>1. Download from AUR using <code>yay</code></strong></p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yay</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> micromamba-bin</span></span></code></pre></div><p><strong>2. Initialization</strong></p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">micromamba</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> shell</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> init</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bash</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>If step 2 fails, run this before running the same step again: <code>export MAMBA_ROOT_PREFIX=~/micromamba</code></p></div><p><strong>3. Verify</strong></p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">source</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.bashrc</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">micromamba</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span></span></code></pre></div><h2 id="core-workflow" tabindex="-1">Core Workflow <a class="header-anchor" href="#core-workflow" aria-label="Permalink to ŌĆ£Core WorkflowŌĆØ">ŌĆŗ</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Don&#39;t &quot;brainlessly&quot; run the following commands, since you need to replace the &lt;&gt; values.</p></div><h3 id="environment-management" tabindex="-1">Environment Management <a class="header-anchor" href="#environment-management" aria-label="Permalink to ŌĆ£Environment ManagementŌĆØ">ŌĆŗ</a></h3><ul><li><code>micromamba create --name &lt;env_name&gt; python=&lt;python_version&gt;</code>: Create an environment</li><li><code>micromamba activate &lt;env_name&gt;</code>: Activate an environment</li><li><code>micromamba deactivate</code>: Deactivate the current environment</li><li><code>micromamba env list</code>: List all environments</li><li><code>micromamba env remove --name &lt;env_name&gt;</code>: Remove an environment</li><li><code>micromamba env export &gt; &lt;filename&gt;.yml</code>: Environment export to a <code>.yml</code> file</li><li><code>micromamba env create -f &lt;filename&gt;.yml</code>: Build an environment from a <code>.yml</code> file</li></ul><h3 id="package-management" tabindex="-1">Package Management <a class="header-anchor" href="#package-management" aria-label="Permalink to ŌĆ£Package ManagementŌĆØ">ŌĆŗ</a></h3><ul><li><code>micromamba install &lt;package_name&gt;</code>: Install a package</li><li><code>micromamba install &lt;package_name=version_number&gt;</code>: Install a specific package version</li><li><code>micromamba list</code>: List installed packages</li><li><code>micromamba update &lt;package_name&gt;</code>: Update a package</li><li><code>micromamba search &lt;package_name&gt;</code>: Search for a package</li><li><code>micromamba clean --all</code>: Clean up cache to save space</li></ul><hr><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>Micromamba also allows you to run a command inside an environment without activating it first:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">micromamba</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">env_nam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> python</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">script_nam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">.py</span></span></code></pre></div></div>`,20)])])}const g=i(l,[["render",o]]);export{k as __pageData,g as default};
